body.script:
                    (() => {
                        'use strict';

                        /* ── State ── */
                        const state = {
                            tracking:    false,
                            watchId:     null,
                            heartbeatId: null,
                            timerId:     null,
                            lastPayload: null,
                            trackingStart: null,
                        };

                        /* ── DOM refs ── */
                        const $  = (id) => document.getElementById(id);
                        const el = {
                            startButton:       $('startButton'),
                            stopButton:        $('stopButton'),
                            statusBadge:       $('statusBadge'),
                            statusDot:         $('statusDot'),
                            statusLabel:       $('statusLabel'),
                            noticeBox:         $('noticeBox'),
                            lastSeenValue:     $('lastSeenValue'),
                            latitudeValue:     $('latitudeValue'),
                            longitudeValue:    $('longitudeValue'),
                            locationNameValue: $('locationNameValue'),
                            accuracyValue:     $('accuracyValue'),
                            takingTimeValue:   $('takingTimeValue'),
                            mapButton:         $('mapButton'),
                        };

                        /* ── Helpers ── */
                        const updateStatus = (status, label) => {
                            const s = status || 'offline';
                            el.statusBadge.className = `status-badge badge-${s}`;
                            el.statusDot.className   = `status-dot dot-${s}`;
                            el.statusLabel.textContent = label || 'Offline';
                        };

                        const setNotice = (type, title, message) => {
                            // type: '' | 'success' | 'warning' | 'danger'
                            el.noticeBox.className = `notice${type ? ' notice-' + type : ''}`;
                            el.noticeBox.innerHTML = `${title}${message}`;
                        };

                        const formatDuration = (ms) => {
                            const totalSec = Math.floor(ms / 1000);
                            const h = Math.floor(totalSec / 3600);
                            const m = Math.floor((totalSec % 3600) / 60);
                            const s = totalSec % 60;
                            const pad = (n) => String(n).padStart(2, '0');
                            return h > 0
                                ? `${pad(h)}:${pad(m)}:${pad(s)}`
                                : `${pad(m)}:${pad(s)}`;
                        };

                        const tickTimer = () => {
                            if (!state.trackingStart) return;
                            const elapsed = Date.now() - state.trackingStart;
                            el.takingTimeValue.textContent = formatDuration(elapsed);
                        };

                        const postJson = async (url, payload) => {
                            const res = await fetch(url, {
                                method:      'POST',
                                headers:     { 'Content-Type': 'application/json' },
                                body:        JSON.stringify(payload || {}),
                                credentials: 'same-origin',
                                keepalive:   true,
                            });
                            if (!res.ok) throw new Error(`HTTP ${res.status}`);
                            return res.json();
                        };

                        const openBtn      = document.getElementById('openCameraBtn');
                        const video        = document.getElementById('selfieVideo');
                        const canvas       = document.getElementById('selfieCanvas');
                        const previewBox   = document.getElementById('previewBox');
                        const snapRow      = document.getElementById('snapRow');
                        const camLabel     = document.getElementById('camLabel');
                        const stopBtn      = document.getElementById('stopBtn');
                        const captureBtn   = document.getElementById('captureBtn');
                        const flipBtn      = document.getElementById('flipBtn');
                        const flashEl      = document.getElementById('flashEl');
                        const downloadLink = document.getElementById('downloadLink');
                        const camGallery   = document.getElementById('camGallery');
                        const galleryGrid  = document.getElementById('galleryGrid');
                        const galleryCount = document.getElementById('galleryCount');
                        const clearAllBtn  = document.getElementById('clearAllBtn');
                        const photoViewer  = document.getElementById('photoViewer');
                        const viewerImg    = document.getElementById('viewerImg');
                        const pvBack       = document.getElementById('pvBack');
                        const pvDownload   = document.getElementById('pvDownload');
                        const pvDelete     = document.getElementById('pvDelete');

                        let stream = null;
                        let facingMode = 'user';
                        let photos = [];
                        let viewingIndex = -1;

                        async function startCamera(facing) {
                            if (stream) stream.getTracks().forEach(t => t.stop());
                            try {
                                stream = await navigator.mediaDevices.getUserMedia({
                                    video: { facingMode: facing, width: { ideal: 1280 }, height: { ideal: 960 } }
                                });
                                video.srcObject = stream;
                                previewBox.style.display = 'block';
                                openBtn.style.display = 'none';
                                snapRow.style.display = 'none';
                                camGallery.style.display = 'none';
                                photoViewer.style.display = 'none';
                                camLabel.textContent = 'Tap the shutter button to take a photo';
                            } catch (e) {
                                camLabel.textContent = 'Camera access denied or unavailable.';
                            }
                        }

                        function closeCamera() {
                            if (stream) { stream.getTracks().forEach(t => t.stop()); stream = null; }
                            previewBox.style.display = 'none';
                            openBtn.style.display = 'inline-flex';
                            camLabel.textContent = 'Click to access your camera';
                            if (photos.length > 0) renderGallery();
                        }

                        function renderGallery() {
                            camGallery.style.display = 'flex';
                            galleryCount.textContent = 'Saved photos (' + photos.length + ')';
                            galleryGrid.innerHTML = '';
                            if (photos.length === 0) {
                                galleryGrid.innerHTML = '
No photos yet';
                                return;
                            }
                            photos.forEach(function (p, i) {
                                const img = document.createElement('img');
                                img.src = p.dataUrl;
                                img.title = p.ts;
                                img.addEventListener('click', function () { openViewer(i); });
                                galleryGrid.appendChild(img);
                            });
                        }

                        function openViewer(idx) {
                            viewingIndex = idx;
                            viewerImg.src = photos[idx].dataUrl;
                            camGallery.style.display = 'none';
                            photoViewer.style.display = 'flex';
                            openBtn.style.display = 'none';
                        }

                        /* ── Event listeners ── */

                        openBtn.addEventListener('click', () => startCamera(facingMode));
                        stopBtn.addEventListener('click', closeCamera);

                        flipBtn.addEventListener('click', () => {
                            facingMode = facingMode === 'user' ? 'environment' : 'user';
                            startCamera(facingMode);
                        });

                        captureBtn.addEventListener('click', () => {
                            if (!stream) return;

                            // Flash effect
                            flashEl.classList.add('go');
                            setTimeout(() => flashEl.classList.remove('go'), 160);

                            // Draw frame to canvas
                            canvas.width  = video.videoWidth  || 640;
                            canvas.height = video.videoHeight || 480;
                            const ctx = canvas.getContext('2d');
                            if (facingMode === 'user') {
                                ctx.translate(canvas.width, 0);
                                ctx.scale(-1, 1);
                            }
                            ctx.drawImage(video, 0, 0);
                            const dataUrl = canvas.toDataURL('image/jpeg', 0.92);

                            // Save photo
                            photos.push({ dataUrl: dataUrl, ts: new Date().toLocaleTimeString() });

                            // Set download link
                            downloadLink.href = dataUrl;
                            downloadLink.download = 'photo_' + Date.now() + '.jpg';

                            // Show snap confirmation for 2 seconds then hide
                            snapRow.style.display = 'flex';
                            camLabel.textContent = 'Photo saved! Take another or close camera.';
                            setTimeout(() => { snapRow.style.display = 'none'; }, 2000);

                            // Update gallery in background (camera stays open)
                            renderGallery();
                            // Hide gallery while camera is open
                            camGallery.style.display = 'none';
                        });

                        downloadLink.addEventListener('click', (e) => {
                            e.preventDefault();
                            const a = document.createElement('a');
                            a.href = downloadLink.href;
                            a.download = downloadLink.download;
                            a.click();
                        });

                        pvBack.addEventListener('click', () => {
                            photoViewer.style.display = 'none';
                            camGallery.style.display = 'flex';
                            if (!stream) openBtn.style.display = 'inline-flex';
                        });

                        pvDownload.addEventListener('click', () => {
                            const a = document.createElement('a');
                            a.href = photos[viewingIndex].dataUrl;
                            a.download = 'photo_' + viewingIndex + '.jpg';
                            a.click();
                        });

                        pvDelete.addEventListener('click', () => {
                            photos.splice(viewingIndex, 1);
                            photoViewer.style.display = 'none';
                            renderGallery();
                            if (!stream) openBtn.style.display = 'inline-flex';
                        });

                        clearAllBtn.addEventListener('click', () => {
                            photos = [];
                            renderGallery();
                        });

                        /* ── Tracking logic ── */
                        const sendLocation = async (position) => {
                            const payload = {
                                latitude:  position.coords.latitude,
                                longitude: position.coords.longitude,
                                accuracy:  position.coords.accuracy,
                                speed:     position.coords.speed,
                                heading:   position.coords.heading,
                                source:    'browser',
                            };
                            state.lastPayload = payload;
                            const result = await postJson('/salesperson_tracking/update', payload);
                            refreshMetrics(payload, result);
                            if (!payload.accuracy || Number(payload.accuracy) <= 200) {
                                setNotice('success', 'Tracking active',
                                    ' Odoo is receiving fresh GPS points from this device.');
                            }
                        };

                        const startTracking = async () => {
                            if (!navigator.geolocation) {
                                setNotice('danger', 'Not supported',
                                    ' This browser does not support geolocation.');
                                return;
                            }
                            if (state.tracking) return;
                            state.tracking = true;

                            el.startButton.disabled = true;
                            updateStatus('live', 'Starting…');

                            state.trackingStart = Date.now();
                            el.takingTimeValue.textContent = '00:00';
                            state.timerId = setInterval(tickTimer, 1000);

                            const opts = { enableHighAccuracy: true, maximumAge: 5000, timeout: 15000 };

                            navigator.geolocation.getCurrentPosition(
                                (pos) => sendLocation(pos).catch((e) => setNotice('danger', 'Update failed', ' ' + e.message)),
                                (err) => {
                                    state.tracking = false;
                                    el.startButton.disabled = false;
                                    if (state.timerId !== null) { clearInterval(state.timerId); state.timerId = null; }
                                    state.trackingStart = null;
                                    el.takingTimeValue.textContent = '—';
                                    updateStatus('offline', 'Offline');
                                    setNotice('danger', 'Permission needed',
                                        ' ' + (err.message || 'GPS access was denied.'));
                                },
                                opts
                            );

                            state.watchId = navigator.geolocation.watchPosition(
                                (pos) => sendLocation(pos).catch((e) => setNotice('warning', 'Update failed', ' ' + e.message)),
                                (err) => setNotice('warning', 'Tracking error', ' ' + (err.message || 'Could not read device location.')),
                                opts
                            );

                            state.heartbeatId = setInterval(() => {
                                if (!state.lastPayload) return;
                                postJson('/salesperson_tracking/update', state.lastPayload)
                                    .then((r)  => refreshMetrics(state.lastPayload, r))
                                    .catch((e) => setNotice('warning', 'Heartbeat failed', ' ' + e.message));
                            }, 20000);
                        };

                        const stopTracking = async () => {
                            state.tracking = false;
                            if (state.watchId !== null) {
                                navigator.geolocation.clearWatch(state.watchId);
                                state.watchId = null;
                            }
                            if (state.heartbeatId !== null) {
                                clearInterval(state.heartbeatId);
                                state.heartbeatId = null;
                            }
                            if (state.timerId !== null) {
                                clearInterval(state.timerId);
                                state.timerId = null;
                            }

                            const durationSeconds = state.trackingStart
                                ? Math.floor((Date.now() - state.trackingStart) / 1000)
                                : 0;
                            state.trackingStart = null;

                            el.takingTimeValue.textContent = '—';
                            console.log(el.takingTimeValue.textContent);
                            el.startButton.disabled = false;
                            try {
                                await postJson('/salesperson_tracking/stop', {
                                    duration_seconds: durationSeconds,
                                });
                            } catch (e) {
                                setNotice('warning', 'Stop warning', ' ' + e.message);
                            }
                            updateStatus('offline', 'Offline');
                            setNotice('', 'Tracking stopped',
                                ' This device is no longer sending live position updates.');
                        };


                        /* ── Event listeners ── */
                        el.startButton.addEventListener('click', () =>
                            startTracking().catch((e) => setNotice('danger', 'Start failed', ' ' + e.message)));

                        el.stopButton.addEventListener('click', () =>
                            stopTracking().catch((e) => setNotice('danger', 'Stop failed', ' ' + e.message)));

                        window.addEventListener('pagehide', () => {
                            if (state.tracking) {
                                navigator.sendBeacon(
                                    '/salesperson_tracking/stop',
                                    new Blob(['{}'], { type: 'application/json' })
                                );
                            }
                        });
                    })();

//
(function () {
    var mapEl  = document.getElementById('map');
    var b64    = mapEl.getAttribute('data-points') || '';
    var planB64 = mapEl.getAttribute('data-plans') || '';
    var points = [];
    var plans  = [];

    try { points = JSON.parse(atob(b64));     } catch (e) { points = []; }
    try { plans  = JSON.parse(atob(planB64)); } catch (e) { plans  = []; }

    var DEFAULT_CENTER = [23.7701, 90.4254];
    var map = L.map('map', { zoomControl: true }).setView(DEFAULT_CENTER, 15);

    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '\u00a9 <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
        maxZoom: 19,
    }).addTo(map);

    /* ── No data state ── */
    if (!points || points.length === 0) {
        var nd = document.createElement('div');
        nd.className = 'no-data';
        nd.innerHTML = [
            '<div class="no-data-card">',
            '  <div class="no-data-icon">',
            '    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">',
            '      <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/>',
            '    </svg>',
            '  </div>',
            '  <div class="no-data-title">No location data</div>',
            '  <div class="no-data-sub">No GPS logs available for today.</div>',
            '</div>',
        ].join('');
        document.querySelector('.map-wrapper').appendChild(nd);
        return;
    }

    /* ── Filter extreme inaccuracy ── */
    var valid = points.filter(function (p) {
        return typeof p.lat === 'number' && typeof p.lng === 'number'
              && (p.accuracy <= 2000 || p.accuracy === 0);
    });
    if (valid.length === 0) valid = points;

    /* ── Path polyline ── */
    var latlngs = valid.map(function (p) { return [p.lat, p.lng]; });
    L.polyline(latlngs, {
        color:     '#6366f1',
        weight:    3,
        opacity:   0.85,
        dashArray: '7 5',
    }).addTo(map);

    /* ── Accuracy circles + intermediate markers ── */
    valid.forEach(function (p, i) {
        if (p.accuracy > 0 && p.accuracy <= 500) {
            L.circle([p.lat, p.lng], {
                radius:      p.accuracy,
                color:       '#3b82f6',
                fillColor:   '#3b82f6',
                fillOpacity: 0.1,
                weight:      1,
                opacity:     0.35,
            }).addTo(map);
        }

        if (i > 0 && i < valid.length - 1) {
            var dot = L.circleMarker([p.lat, p.lng], {
                radius:      5,
                color:       '#6366f1',
                fillColor:   '#c7d2fe',
                fillOpacity: 1,
                weight:      2,
            });
            var timeStr  = p.time  ? p.time.replace('T', ' ') : '—';
            var speedStr = p.speed ? (p.speed * 3.6).toFixed(1) + ' km/h' : '0 km/h';
            var accStr   = p.accuracy ? p.accuracy.toFixed(1) + ' m' : '—';
            dot.bindPopup(
                '<b>Time:</b> '     + timeStr  + '<br>' +
                '<b>Speed:</b> '    + speedStr + '<br>' +
                '<b>Accuracy:</b> ' + accStr   +
                (p.location_name ? '<br><b>Location:</b> ' + p.location_name : '')
            );
            dot.addTo(map);
        }
    });

    /* ── Start marker ── */
    var sp = valid[0];
    L.marker([sp.lat, sp.lng], {
        icon: L.divIcon({
            html: '<div style="width:18px;height:18px;background:#3b6d11;border-radius:50%;border:3px solid #fff;box-shadow:0 2px 8px rgba(0,0,0,.25)"></div>',
            iconSize:   [18, 18],
            iconAnchor: [9, 9],
            className:  '',
        }),
    }).addTo(map).bindPopup(
        '<b>Start point</b><br>' + (sp.time || '') +
        (sp.location_name ? '<br>' + sp.location_name : '')
    );

    /* ── End / current marker ── */
    var ep = valid[valid.length - 1];
    L.marker([ep.lat, ep.lng], {
        icon: L.divIcon({
            html: '<div style="width:22px;height:22px;background:#dc2626;border-radius:50% 50% 50% 0;transform:rotate(-45deg);border:3px solid #fff;box-shadow:0 2px 10px rgba(0,0,0,.3)"></div>',
            iconSize:   [22, 22],
            iconAnchor: [11, 22],
            className:  '',
        }),
    }).addTo(map).bindPopup(
        '<b>Current / last position</b><br>' +
        (ep.time || '') +
        (ep.location_name ? '<br>' + ep.location_name : '') +
        '<br>Accuracy: ' + (ep.accuracy ? ep.accuracy.toFixed(1) + ' m' : '—')
    ).openPopup();

    /* ── Plan markers ── */
    if (plans && plans.length > 0) {
        plans.forEach(function (pl) {
            if (typeof pl.lat !== 'number' || typeof pl.lng !== 'number') return;
            var visited = !!pl.visited;
            var color   = visited ? '#3b6d11' : '#dc2626';
            var opacity = visited ? 0.55 : 0.45;
            var dot = L.circleMarker([pl.lat, pl.lng], {
                radius:      7,
                color:       color,
                fillColor:   color,
                fillOpacity: opacity,
                weight:      2,
            });
            dot.bindPopup(
                '<b>' + (pl.name || 'Planned location') + '</b><br>' +
                (visited ? '&#10003; Visited' : '&#8226; Not visited yet') +
                (pl.address ? '<br>' + pl.address : '')
            );
            dot.addTo(map);
        });
    }

    /* ── Fit bounds ── */
    var allLatLngs = latlngs.slice();
    if (plans) {
        plans.forEach(function (pl) {
            if (typeof pl.lat === 'number' && typeof pl.lng === 'number') {
                allLatLngs.push([pl.lat, pl.lng]);
            }
        });
    }

    if (allLatLngs.length > 1) {
        map.fitBounds(L.latLngBounds(allLatLngs), { padding: [50, 50] });
    } else {
        map.setView(latlngs[0], 16);
    }

    setTimeout(function () { map.invalidateSize(); }, 300);
})();
